const cita = validas[0].json;
return [{ json: { ...datos, accion: 'respuesta_directa', respuesta: '📋 Tu próxima cita:\n📅 '+cita.fecha+'\n🕐 '+(cita.hora||'').substring(0,5)+' hs\n✂️ Barbero: '+cita.barbero+'\n👨 '+cita.servicio+'\n\nPara cancelar escribí *cancelar*.' } }];

const d = $input.first().json;
const ahora = new Date().toISOString();
let estadoConv = 'en_progreso';
let esperandoConf = false;
let esperandoBarbero = false;
let barberos_disp = '[]';
if (d.accion === 'completado') estadoConv = 'completado';
else if (d.accion === 'esperando_confirmacion') esperandoConf = true;
else if (d.accion === 'esperando_barbero') { esperandoBarbero = true; barberos_disp = d.barberos_disponibles || '[]'; }
return [{ json: {
  shop_id: d.shop_id,
  chat_id: d.chat_id,
  telefono: d.telefono || '',
  estado_conversacion: estadoConv,
  nombre_parcial: (d.contexto_previo && d.contexto_previo.nombre) ? d.contexto_previo.nombre : (d.nombre_guardado || ''),
  fecha_parcial: d.fecha_turno || '',
  hora_parcial: d.hora_turno || '',
  servicio_parcial: d.servicio || 'Corte de cabello',
  barbero_parcial: d.barbero_elegido || '',
  esperando_confirmacion: esperandoConf,
  esperando_barbero: esperandoBarbero,
  barberos_disponibles: barberos_disp,
  ultima_actualizacion: ahora,
  ultimo_mensaje: d.respuesta || '',
  respuesta: d.respuesta || ''
}}];

const d = $input.first().json;
const SUPABASE_URL = 'https://mmokunpuslcfphalrwot.supabase.co';
const SUPABASE_KEY = 'REEMPLAZA_CON_TU_ANON_KEY';

const payload = {
  shop_id: d.shop_id,
  chat_id: d.chat_id,
  telefono: d.telefono || '',
  estado_conversacion: d.estado_conversacion,
  nombre_parcial: d.nombre_parcial || '',
  fecha_parcial: d.fecha_parcial || '',
  hora_parcial: d.hora_parcial || '',
  servicio_parcial: d.servicio_parcial || 'Corte de cabello',
  barbero_parcial: d.barbero_parcial || '',
  esperando_confirmacion: d.esperando_confirmacion,
  esperando_barbero: d.esperando_barbero,
  barberos_disponibles: d.barberos_disponibles || '[]',
  ultima_actualizacion: d.ultima_actualizacion,
  ultimo_mensaje: d.ultimo_mensaje || ''
};

await $http.request({
  method: 'POST',
  url: SUPABASE_URL + '/rest/v1/conversaciones?on_conflict=chat_id,shop_id',
  headers: {
    'apikey': SUPABASE_KEY,
    'Authorization': 'Bearer ' + SUPABASE_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'resolution=merge-duplicates,return=minimal'
  },
  body: payload,
  json: true
});

return [{ json: { chat_id: d.chat_id, shop_id: d.shop_id, respuesta: d.respuesta } }];

const hoy = new Date().toISOString().split('T')[0];
const citas = $input.all().map(function(item) {
  const r = item.json;
  return { id: r.id, Nombre: r.nombre || '', Hora: (r.hora || '00:00').substring(0,5), Servicio: r.servicio || 'Corte', Barbero: r.barbero || '', Telefono: r.telefono || '', Fecha: r.fecha || hoy, Estado: r.estado || 'Confirmada' };
});
return [{ json: { citas: citas, total: citas.length, fecha: hoy, timestamp: new Date().toISOString() } }];

const TIMEZONE = 'America/Santo_Domingo';
const now = new Date();
const nowLocal = new Date(now.toLocaleString('en-US', { timeZone: TIMEZONE }));
const hoy = nowLocal.toISOString().split('T')[0];
const recordatorios = [];
const noShows = [];
for (const item of $input.all()) {
  const row = item.json;
  if (!row.fecha || !row.hora || row.estado !== 'Confirmada') continue;
  if (row.fecha !== hoy) continue;
  const horaStr = (row.hora || '00:00').substring(0,5);
  const citaDate = new Date(row.fecha + 'T' + horaStr + ':00');
  if (isNaN(citaDate.getTime())) continue;
  const diffMin = (citaDate - nowLocal) / (1000 * 60);
  if (diffMin > 55 && diffMin <= 65) {
    recordatorios.push({ tipo: 'recordatorio', shop_id: row.shop_id, telefono: row.telefono, chat_id: row.chat_id || row.telefono, nombre: row.nombre, fecha: row.fecha, hora: horaStr, servicio: row.servicio, barbero: row.barbero || '' });
  }
  if (diffMin < -40 && diffMin >= -55) {
    noShows.push({ tipo: 'no_show', shop_id: row.shop_id, telefono: row.telefono, chat_id: row.chat_id || row.telefono, nombre: row.nombre, fecha: row.fecha, hora: horaStr, servicio: row.servicio, barbero: row.barbero || '', cita_id: row.id });
  }
}
const todos = recordatorios.concat(noShows);
if (todos.length === 0) return [];
return todos.map(x => ({ json: x }));
